import os
import requests

def load_model_from_cloud(model_path):
    response = requests.get(model_path)
    if response.status_code == 200:
        with open('model.pkl', 'wb') as f:
            f.write(response.content)
        print("Model loaded successfully.")
    else:
        print(f"Failed to load model. Status code: {response.status_code}")

if __name__ == "__main__":
    model_path = os.getenv("MODEL_PATH")
    if not model_path:
        raise ValueError("Model path must be provided via MODEL_PATH environment variable.")
    
    load_model_from_cloud(model_path)